// ============================================
// PARTICLE SYSTEM
// ============================================
const canvas = document.getElementById('particle-canvas');
const ctx = canvas.getContext('2d');
let particles = [];

function resizeCanvas() {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
}
resizeCanvas();
window.addEventListener('resize', resizeCanvas);

class Particle {
    constructor() {
        this.reset();
    }
    reset() {
        this.x = Math.random() * canvas.width;
        this.y = canvas.height + 10;
        this.size = Math.random() * 4 + 1;
        this.speedY = -(Math.random() * 1.5 + 0.5);
        this.speedX = (Math.random() - 0.5) * 0.5;
        this.opacity = Math.random() * 0.6 + 0.2;
        this.type = Math.random() < 0.3 ? 'heart' : 'sparkle';
        this.rotation = Math.random() * Math.PI * 2;
        this.rotSpeed = (Math.random() - 0.5) * 0.05;
    }
    update() {
        this.y += this.speedY;
        this.x += this.speedX;
        this.rotation += this.rotSpeed;
        if (this.y < -20) this.reset();
    }
    draw() {
        ctx.save();
        ctx.globalAlpha = this.opacity;
        ctx.translate(this.x, this.y);
        ctx.rotate(this.rotation);
        if (this.type === 'heart') {
            ctx.fillStyle = '#c2185b';
            ctx.font = `${this.size * 4}px serif`;
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';
            ctx.fillText('❤', 0, 0);
        } else {
            ctx.fillStyle = '#f4c430';
            ctx.beginPath();
            for (let i = 0; i < 5; i++) {
                const angle = (i * Math.PI * 4) / 5 - Math.PI / 2;
                const r = i % 2 === 0 ? this.size * 2 : this.size;
                if (i === 0) ctx.moveTo(Math.cos(angle) * r, Math.sin(angle) * r);
                else ctx.lineTo(Math.cos(angle) * r, Math.sin(angle) * r);
            }
            ctx.closePath();
            ctx.fill();
        }
        ctx.restore();
    }
}

for (let i = 0; i < 60; i++) {
    const p = new Particle();
    p.y = Math.random() * canvas.height;
    particles.push(p);
}

function animateParticles() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    particles.forEach(p => { p.update(); p.draw(); });
    requestAnimationFrame(animateParticles);
}
animateParticles();

// ============================================
// HEART RAIN - Click Effect
// ============================================
const heartCanvas = document.getElementById('heart-canvas');
const heartCtx = heartCanvas.getContext('2d');
let heartParticlesArr = [];

function resizeHeartCanvas() {
    heartCanvas.width = window.innerWidth;
    heartCanvas.height = window.innerHeight;
}
resizeHeartCanvas();
window.addEventListener('resize', resizeHeartCanvas);

function createHeartBurst(x, y, count = 20) {
    const colors = ['#c2185b', '#e91e8c', '#f4c430', '#ff6b9d', '#fff', '#ad1457'];
    for (let i = 0; i < count; i++) {
        const angle = (Math.random() * Math.PI * 2);
        const speed = Math.random() * 3 + 1;
        heartParticlesArr.push({
            x, y,
            vx: Math.cos(angle) * speed,
            vy: Math.sin(angle) * speed - 3,
            size: Math.random() * 16 + 8,
            opacity: 1,
            color: colors[Math.floor(Math.random() * colors.length)],
            type: Math.random() < 0.7 ? '❤' : '✨',
            life: 1,
            decay: Math.random() * 0.02 + 0.01,
            rotation: Math.random() * Math.PI * 2,
            rotSpeed: (Math.random() - 0.5) * 0.2,
        });
    }
}

function triggerHeartRain(count = 30) {
    const colors = ['#c2185b', '#e91e8c', '#f4c430', '#ff6b9d', '#ad1457'];
    for (let i = 0; i < count; i++) {
        setTimeout(() => {
            heartParticlesArr.push({
                x: Math.random() * window.innerWidth,
                y: -20,
                vx: (Math.random() - 0.5) * 2,
                vy: Math.random() * 3 + 2,
                size: Math.random() * 20 + 10,
                opacity: 1,
                color: colors[Math.floor(Math.random() * colors.length)],
                type: '❤',
                life: 1,
                decay: 0.005,
                rotation: Math.random() * Math.PI * 2,
                rotSpeed: (Math.random() - 0.5) * 0.1,
                falling: true,
            });
        }, i * 50);
    }
}

function animateHearts() {
    heartCtx.clearRect(0, 0, heartCanvas.width, heartCanvas.height);
    heartParticlesArr = heartParticlesArr.filter(p => p.life > 0);
    heartParticlesArr.forEach(p => {
        p.x += p.vx;
        p.y += p.falling ? p.vy : p.vy;
        p.vy += p.falling ? 0.1 : -0.05;
        p.life -= p.decay;
        p.rotation += p.rotSpeed;
        heartCtx.save();
        heartCtx.globalAlpha = p.life;
        heartCtx.translate(p.x, p.y);
        heartCtx.rotate(p.rotation);
        heartCtx.font = `${p.size}px serif`;
        heartCtx.textAlign = 'center';
        heartCtx.textBaseline = 'middle';
        heartCtx.fillStyle = p.color;
        heartCtx.fillText(p.type, 0, 0);
        heartCtx.restore();
    });
    requestAnimationFrame(animateHearts);
}
animateHearts();

// Clicking anywhere creates hearts
document.addEventListener('click', (e) => {
    if (e.target.tagName === 'BUTTON' || e.target.tagName === 'A') return;
    createHeartBurst(e.clientX, e.clientY, 25);
});
document.addEventListener('touchend', (e) => {
    const touch = e.changedTouches[0];
    createHeartBurst(touch.clientX, touch.clientY, 15);
});

// ============================================
// MUSIC PLAYER
// ============================================
let audioCtx = null;
let musicInterval = null;

function toggleMusic() {
    const player = document.getElementById('music-player');
    if (!musicPlaying) {
        playBirthdayTune();
        player.querySelector('.music-label').textContent = '♪ Playing...';
        player.style.background = 'rgba(194,24,91,0.3)';
        musicPlaying = true;
    } else {
        stopMusic();
        player.querySelector('.music-label').textContent = 'Birthday Music';
        player.style.background = 'rgba(0,0,0,0.6)';
        musicPlaying = false;
    }
}

document.getElementById('music-player').addEventListener('click', toggleMusic);

function playBirthdayTune() {
    try {
        audioCtx = new (window.AudioContext || window.webkitAudioContext)();
        // "Happy Birthday" melody with frequencies
        const notes = [
            [261.63, 0.3], [261.63, 0.1], [293.66, 0.4], [261.63, 0.4], [349.23, 0.4], [329.63, 0.8],
            [261.63, 0.3], [261.63, 0.1], [293.66, 0.4], [261.63, 0.4], [392.00, 0.4], [349.23, 0.8],
            [261.63, 0.3], [261.63, 0.1], [523.25, 0.4], [440.00, 0.4], [349.23, 0.4], [329.63, 0.4], [293.66, 0.8],
            [466.16, 0.3], [466.16, 0.1], [440.00, 0.4], [349.23, 0.4], [392.00, 0.4], [349.23, 0.8],
        ];
        let time = audioCtx.currentTime;
        notes.forEach(([freq, duration]) => {
            const osc = audioCtx.createOscillator();
            const gain = audioCtx.createGain();
            osc.connect(gain);
            gain.connect(audioCtx.destination);
            osc.type = 'sine';
            osc.frequency.value = freq;
            gain.gain.setValueAtTime(0, time);
            gain.gain.linearRampToValueAtTime(0.15, time + 0.05);
            gain.gain.linearRampToValueAtTime(0, time + duration - 0.05);
            osc.start(time);
            osc.stop(time + duration);
            time += duration;
        });
        // Loop after tune ends
        musicInterval = setTimeout(() => {
            if (musicPlaying) playBirthdayTune();
        }, time * 1000 + 500 - audioCtx.currentTime * 1000);
    } catch (e) { console.log('Audio not supported'); }
}

function stopMusic() {
    if (audioCtx) { try { audioCtx.close(); } catch (e) { } audioCtx = null; }
    if (musicInterval) { clearTimeout(musicInterval); musicInterval = null; }
}

// ============================================
// BIRTHDAY CAKE - BLOW CANDLES
// ============================================
function blowCandles() {
    if (candlesBlown) return;
    candlesBlown = true;

    // Blow out candles with stagger
    for (let i = 1; i <= 5; i++) {
        setTimeout(() => {
            const flame = document.getElementById(`flame${i}`);
            if (flame) flame.classList.add('blown-out');
        }, i * 200);
    }

    // Show wish and sparkles
    setTimeout(() => {
        document.getElementById('cake-wish').classList.add('show');
        createHeartBurst(window.innerWidth / 2, window.innerHeight / 2, 40);
        triggerHeartRain(20);
    }, 1200);
}

// ============================================
// GALLERY LIGHTBOX
// ============================================
function openLightbox(index) {
    currentLightboxIndex = index;
    const lb = document.getElementById('lightbox');
    const img = document.getElementById('lightbox-img');
    img.src = galleryPhotos[index].src;
    lb.classList.add('active');
    document.body.classList.add('no-scroll');
}

function closeLightbox() {
    document.getElementById('lightbox').classList.remove('active');
    document.body.classList.remove('no-scroll');
}

function changeLightboxImage(dir) {
    currentLightboxIndex = (currentLightboxIndex + dir + galleryPhotos.length) % galleryPhotos.length;
    document.getElementById('lightbox-img').src = galleryPhotos[currentLightboxIndex].src;
}

document.getElementById('lightbox').addEventListener('click', (e) => {
    if (e.target === e.currentTarget) closeLightbox();
});

// Keyboard navigation for lightbox
document.addEventListener('keydown', (e) => {
    if (!document.getElementById('lightbox').classList.contains('active')) return;
    if (e.key === 'Escape') closeLightbox();
    if (e.key === 'ArrowLeft') changeLightboxImage(-1);
    if (e.key === 'ArrowRight') changeLightboxImage(1);
});

// ============================================
// LOVE WALL - FLOATING MESSAGES
// ============================================
const messages = [
    "❤️ You are my favorite person.",
    "💕 Thank you for being you.",
    "🌸 Every day is better with you.",
    "✨ My greatest blessing.",
    "💝 You make me whole.",
    "🌙 I love your beautiful soul.",
    "🌹 You are my sunshine.",
    "💫 Forever in love with you.",
    "🦋 You inspire me every day.",
    "🌺 My heart belongs to you.",
];

const wallContainer = document.getElementById('love-wall-container');
messages.forEach((msg, i) => {
    const el = document.createElement('div');
    el.className = 'floating-message';
    el.textContent = msg;
    const positions = [
        [5, 10], [25, 60], [45, 20], [65, 70], [80, 30],
        [15, 80], [50, 50], [70, 10], [35, 40], [55, 80],
    ];
    const [left, top] = positions[i] || [Math.random() * 80, Math.random() * 80];
    el.style.left = `${left}%`;
    el.style.top = `${top}%`;
    el.style.animationDelay = `${i * 0.6}s`;
    el.style.animationDuration = `${4 + Math.random() * 3}s`;
    wallContainer.appendChild(el);
});

// Mouse parallax on love wall
wallContainer.addEventListener('mousemove', (e) => {
    const rect = wallContainer.getBoundingClientRect();
    const mx = (e.clientX - rect.left - rect.width / 2) / rect.width;
    const my = (e.clientY - rect.top - rect.height / 2) / rect.height;
    wallContainer.querySelectorAll('.floating-message').forEach((el, i) => {
        const factor = (i % 3 + 1) * 8;
        el.style.transform = `translate(${mx * factor}px, ${my * factor}px)`;
    });
});
wallContainer.addEventListener('mouseleave', () => {
    wallContainer.querySelectorAll('.floating-message').forEach(el => {
        el.style.transform = '';
    });
});

// ============================================
// COUNTERS - ANIMATED COUNT UP
// ============================================
function animateCounter(el) {
    if (el.dataset.special) return;
    const target = parseInt(el.dataset.target);
    const suffix = el.dataset.suffix || '';
    const duration = 2000;
    const step = target / (duration / 16);
    let current = 0;
    const timer = setInterval(() => {
        current += step;
        if (current >= target) {
            current = target;
            clearInterval(timer);
        }
        el.textContent = Math.floor(current).toLocaleString() + suffix;
    }, 16);
}

// ============================================
// CONFETTI
// ============================================
function launchConfetti(count = 60) {
    const colors = ['#c2185b', '#e91e8c', '#f4c430', '#ff6b9d', '#fff', '#ad1457', '#7b68ee', '#50fa7b'];
    for (let i = 0; i < count; i++) {
        setTimeout(() => {
            const piece = document.createElement('div');
            piece.className = 'confetti-piece';
            piece.style.left = Math.random() * 100 + 'vw';
            piece.style.top = '-20px';
            piece.style.background = colors[Math.floor(Math.random() * colors.length)];
            piece.style.width = (Math.random() * 8 + 6) + 'px';
            piece.style.height = (Math.random() * 8 + 6) + 'px';
            piece.style.borderRadius = Math.random() > 0.5 ? '50%' : '0';
            piece.style.animationDuration = (Math.random() * 2 + 2) + 's';
            piece.style.animationDelay = Math.random() * 0.5 + 's';
            document.body.appendChild(piece);
            setTimeout(() => piece.remove(), 4000);
        }, i * 30);
    }
}

// ============================================
// SURPRISE TRIGGER
// ============================================
function triggerSurprise() {
    if (surpriseTriggered) return;
    surpriseTriggered = true;

    const btn = document.getElementById('surprise-btn');
    btn.style.display = 'none';

    // 1. Screen glow
    const glow = document.getElementById('screen-glow');
    glow.classList.add('active');
    setTimeout(() => glow.classList.remove('active'), 1000);

    // 2. Heart explosion
    createHeartBurst(window.innerWidth / 2, window.innerHeight / 2, 60);

    // 3. Confetti
    setTimeout(() => launchConfetti(80), 300);

    // 4. Heart rain
    setTimeout(() => triggerHeartRain(50), 600);

    // 5. Reveal content
    setTimeout(() => {
        document.getElementById('surprise-reveal').classList.add('active');
    }, 800);

    // Music intensify
    if (!musicPlaying) toggleMusic();
}

function startSurprise() {
    document.getElementById('surprise').scrollIntoView({ behavior: 'smooth' });
    setTimeout(triggerSurprise, 800);
}

function replaySurprise() {
    surpriseTriggered = false;
    candlesBlown = false;
    document.getElementById('surprise-reveal').classList.remove('active');
    document.getElementById('surprise-btn').style.display = '';
    document.getElementById('cake-wish').classList.remove('show');
    document.querySelectorAll('.candle-flame').forEach(f => f.classList.remove('blown-out'));
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setTimeout(() => {
        triggerHeartRain(30);
        launchConfetti(40);
    }, 1000);
}

